
"use client";
import { useState, useEffect } from "react";
import Image from 'next/image';
import AdminSidebar from '@/components/admin/AdminSidebar';
import { getAttendancesAction, getUsersAction, getSubjectsAction, getLabsAction } from "@/app/actions/dbActions";
import { Attendance, User, Subject, Lab } from "@/utils/storage";
import { Card, CardContent } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";

export default function AttendanceReportPage() {
    const [records, setRecords] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            try {
                const [attendances, users, subjects, labs] = await Promise.all([
                    getAttendancesAction(),
                    getUsersAction(),
                    getSubjectsAction(),
                    getLabsAction()
                ]);

                const populatedRecords = attendances.map(att => {
                    const student = users.find(u => u.id === att.studentId);
                    const subject = subjects.find(s => s.id === att.subjectId);
                    // This part needs more info if we want to link attendance to a specific lab request to find the lab
                    return {
                        ...att,
                        studentName: student?.name || 'Unknown',
                        subjectName: subject?.name || 'Unknown',
                        teacherName: subject?.teacherName || 'Unknown',
                        // lab info might not be directly available on attendance record
                    };
                }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

                setRecords(populatedRecords);
            } catch (e) {
                console.error(e);
            } finally {
                setLoading(false);
            }
        }
        fetchData();
    }, []);

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="mb-8">
                        <h1 className="text-3xl font-bold text-gray-800">Attendance Report</h1>
                        <p className="text-muted-foreground">Comprehensive logs of all students who used LAB/rooms.</p>
                    </div>
                    <Card>
                        <CardContent className="pt-6">
                            {loading ? <p>Loading reports...</p> : (
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead>Date</TableHead>
                                            <TableHead>Student</TableHead>
                                            <TableHead>Subject</TableHead>
                                            <TableHead>Teacher</TableHead>
                                            <TableHead>Time In</TableHead>
                                            <TableHead>Time Out</TableHead>
                                            <TableHead>Status</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {records.map(rec => (
                                            <TableRow key={rec.id}>
                                                <TableCell>{new Date(rec.date).toLocaleString()}</TableCell>
                                                <TableCell>{rec.studentName}</TableCell>
                                                <TableCell>{rec.subjectName}</TableCell>
                                                <TableCell>{rec.teacherName}</TableCell>
                                                <TableCell>{rec.timeIn || '-'}</TableCell>
                                                <TableCell>{rec.timeOut || '-'}</TableCell>
                                                <TableCell>
                                                    <Badge variant={rec.status === 'present' ? 'secondary' : 'destructive'} 
                                                        className={rec.status === 'present' ? 'text-green-800 bg-green-100' : ''}>
                                                        {rec.status}
                                                    </Badge>
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            )}
                        </CardContent>
                    </Card>
                </main>
            </div>
        </div>
    );
}
